// ========================================
// Parse request + decode JWT
// ========================================
const headers = $('Webhook RAG').first().json.headers || {};
const body = $('Webhook RAG').first().json.body || {};

const authHeader = headers.authorization || headers.Authorization || '';
const token = authHeader.replace('Bearer ', '');

if (!token) {
  return [{ json: { error: true, message: 'Thiếu token xác thực', status: 401 } }];
}

let userId = null;
try {
  const payload = JSON.parse(Buffer.from(token.split('.')[1], 'base64').toString());
  userId = payload.sub;
  if (!userId) throw new Error('Không có user ID');
} catch (e) {
  return [{ json: { error: true, message: 'Token không hợp lệ', status: 401 } }];
}

if (!body.query || body.query.trim().length < 3) {
  return [{ json: { error: true, message: 'Câu hỏi quá ngắn (tối thiểu 3 ký tự)', status: 400 } }];
}

return [{
  json: {
    error: false,
    user_id: userId,
    query: body.query.trim(),
    session_id: body.session_id || null,
    response_language: body.response_language || 'vi',
    conversation_history: body.conversation_history || [],
    filters: {
      language_preference: body.filters?.language_preference || 'any',
      document_type: body.filters?.document_type || null,
      source_type: body.filters?.source_type || null,
      source_category: body.filters?.source_category || null,
      max_trust_level: Number.isInteger(body.filters?.max_trust_level) ? body.filters.max_trust_level : null,
      equipment_type: body.filters?.equipment_type || null,
      equipment_code: body.filters?.equipment_code || null
    }
  }
}];

// Kiểm tra quyền AI query
const results = $input.all();
const roles = results.map(item => item.json.role_name);
const userEmail = results[0]?.json?.email || 'unknown';
const prevData = $('Parse + JWT Decode').first().json;

const canQuery = roles.some(r => ['admin', 'qa_manager', 'validation', 'engineering'].includes(r));

if (roles.length === 0 || !canQuery) {
  return [{ json: { error: true, message: 'Bạn không có quyền sử dụng AI Search', status: 403 } }];
}

return [{ json: { ...prevData, user_email: userEmail, user_roles: roles, primary_role: roles[0] } }];

