// Parse kết quả Query Expansion — FAIL-SAFE: lỗi/parse hỏng -> dùng query gốc
const ai = $input.first().json;
const prev = $('Check AI Permission').first().json;
const original = prev.query;

let embeddingQuery = original;
let ftsTerms = original;
let expansionUsed = false;

try {
  const raw = ai.choices?.[0]?.message?.content || '';
  const cleaned = raw.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  if (parsed.embedding_query && String(parsed.embedding_query).trim().length >= 3) {
    embeddingQuery = String(parsed.embedding_query).trim();
    expansionUsed = true;
  }
  if (parsed.fts_terms && String(parsed.fts_terms).trim().length >= 2) {
    ftsTerms = String(parsed.fts_terms).trim();
  }
} catch (e) {
  // giữ nguyên query gốc
}

// Neo ý định: embedding gồm cả câu hỏi gốc + phần mở rộng (tránh trôi nghĩa)
const embedInput = expansionUsed ? (original + ' ' + embeddingQuery) : original;

return [{ json: {
  ...prev,
  original_query: original,
  embedding_query: embedInput,
  fts_terms: ftsTerms,
  expansion_used: expansionUsed
}}];

// ========================================
// Tạo SQL hybrid_search_v3 (governance + full-text + trust + quality)
// Over-retrieve (RERANK_POOL) để reranker chọn lọc lại.
// ========================================
const embedResult = $input.first().json;
const prevData = $('Parse Expansion').first().json;

const embedding = embedResult.data?.[0]?.embedding;
if (!embedding) {
  return [{ json: { error: true, message: 'Không tạo được embedding', status: 500 } }];
}
const embStr = '[' + embedding.join(',') + ']';
const f = prevData.filters || {};

// --- Tunables ---
const RERANK_POOL    = 24;   // số ứng viên lấy về để rerank
const MATCH_THRESHOLD = 0.4; // ngưỡng vector (rộng để recall cao, rerank lo precision)
const MIN_QUALITY     = 0.3; // loại chunk nhiễu

const esc = (s) => String(s).replace(/'/g, "''");
const ftsText = prevData.fts_terms || prevData.original_query || '';

// Thứ tự tham số v3:
// (embedding, query_text, match_threshold, match_count, user_id,
//  language_preference, source_category, document_type, max_trust_level,
//  equipment_type, min_quality)
const sql = `SELECT * FROM hybrid_search_v3(
  '${embStr}'::vector(1536),
  '${esc(ftsText)}',
  ${MATCH_THRESHOLD},
  ${RERANK_POOL},
  '${prevData.user_id}'::uuid,
  '${esc(f.language_preference || 'any')}',
  '${esc(f.source_category || 'any')}',
  ${f.document_type ? "'" + esc(f.document_type) + "'" : 'NULL'},
  ${Number.isInteger(f.max_trust_level) ? f.max_trust_level : 5},
  ${f.equipment_type ? "'" + esc(f.equipment_type) + "'" : 'NULL'},
  ${MIN_QUALITY}
);`;

return [{ json: { ...prevData, search_sql: sql, rerank_pool: RERANK_POOL } }];

// Gom kết quả search (N item -> 1) + lọc mềm source_type + dựng prompt rerank
const rows = $input.all().map(i => i.json).filter(r => r && r.chunk_id);
const prevData = $('Build Search SQL').first().json;
const f = prevData.filters || {};

// v3 KHÔNG có tham số source_type -> lọc mềm tại đây để giữ tương thích filter cũ
let candidates = rows;
if (f.source_type) {
  const filtered = rows.filter(r => r.source_type === f.source_type);
  if (filtered.length > 0) candidates = filtered; // chỉ áp dụng nếu không làm rỗng
}

// Gắn chỉ số ổn định cho reranker tham chiếu
candidates = candidates.map((c, i) => ({ ...c, _idx: i }));

const FINAL_TOP_N = 8;
const hasCandidates = candidates.length >= 2; // 0/1 thì khỏi rerank

// Chỉ gửi snippet ngắn để tiết kiệm token
const list = candidates.map(c => {
  const snip = (c.content || '').replace(/\s+/g, ' ').substring(0, 320);
  return `[${c._idx}] (${c.document_code} v${c.document_version} | ${c.source_type} | ${c.language_code} | ${c.lifecycle_state}) ${snip}`;
}).join('\n');

const rerankMessages = [
  { role: 'system', content: 'Bạn là bộ xếp hạng lại (reranker) cho tra cứu tài liệu GMP/validation. Cho một câu hỏi và danh sách đoạn văn (mỗi đoạn có chỉ số [i]), hãy chọn các đoạn LIÊN QUAN NHẤT và xếp theo độ liên quan giảm dần. Ưu tiên đoạn trả lời trực tiếp câu hỏi, đúng thiết bị/ngữ cảnh, có tiêu chí/số liệu cụ thể. CHỈ trả về JSON object thuần.' },
  { role: 'user', content: 'CÂU HỎI:\n' + prevData.original_query + '\n\nCÁC ĐOẠN:\n' + list + '\n\nTrả JSON đúng cấu trúc: {"ranking":[<các chỉ số theo thứ tự liên quan giảm dần, tối đa ' + FINAL_TOP_N + ' số>]}. Chỉ gồm chỉ số có thật trong danh sách; loại đoạn không liên quan.' }
];

return [{ json: {
  ...prevData,
  candidates,
  has_candidates: hasCandidates,
  final_top_n: FINAL_TOP_N,
  rerank_messages: rerankMessages
}}];

// Áp dụng thứ tự rerank — FAIL-SAFE: lỗi -> giữ thứ tự combined_score của v3
const ai = $input.first().json;
const prevData = $('Prepare Rerank').first().json;
const candidates = prevData.candidates || [];
const topN = prevData.final_top_n || 8;
const MIN_KEEP = 3;

let order = null;
try {
  const raw = ai.choices?.[0]?.message?.content || '';
  const cleaned = raw.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  if (Array.isArray(parsed.ranking)) {
    order = parsed.ranking
      .map(n => parseInt(n, 10))
      .filter(n => Number.isInteger(n) && n >= 0 && n < candidates.length);
  }
} catch (e) { order = null; }

let reranked;
let rerankApplied = false;
if (order && order.length > 0) {
  const seen = new Set();
  reranked = [];
  for (const idx of order) {
    if (!seen.has(idx)) { seen.add(idx); reranked.push(candidates[idx]); }
  }
  // Nếu model cắt quá tay -> bù thêm theo combined_score gốc để đủ tối thiểu MIN_KEEP
  if (reranked.length < MIN_KEEP) {
    for (const c of candidates) {
      if (!seen.has(c._idx)) { seen.add(c._idx); reranked.push(c); if (reranked.length >= MIN_KEEP) break; }
    }
  }
  rerankApplied = true;
} else {
  reranked = candidates.slice(); // fallback: thứ tự v3
}

const finalChunks = reranked.slice(0, topN);

return [{ json: { ...prevData, chunks: finalChunks, rerank_applied: rerankApplied } }];

// ========================================
// Xử lý kết quả (đã rerank) + cảnh báo + build context (v3 governance-aware)
// Nhận từ 2 nhánh: Apply Rerank (có .chunks) hoặc Prepare Rerank (0/1 -> .candidates)
// ========================================
const inItem = $input.first().json;
const prevData = $('Build Search SQL').first().json; // carry ổn định ở cả 2 nhánh
const chunks = inItem.chunks || inItem.candidates || [];

if (!chunks || chunks.length === 0) {
  return [{ json: {
    ...prevData,
    chunks: [],
    has_sources: false,
    confidence: 'BLOCKED',
    conflict_warning: '',
    language_warning: '',
    governance_note: '',
    rerank_applied: inItem.rerank_applied || false,
    context_text: 'KHÔNG CÓ CONTEXT CHUNKS. Trả lời: "Không tìm thấy trong nguồn đã được duyệt cho AI."'
  }}];
}

// Conflict: SOP nội bộ vs guideline công khai
let conflictWarning = '';
const hasInternal = chunks.some(c => c.source_type === 'internal_sop');
const hasGuideline = chunks.some(c => c.source_type === 'guideline');
if (hasInternal && hasGuideline) {
  conflictWarning = 'Có cả SOP nội bộ và guideline công khai. Với hồ sơ site, ưu tiên SOP nội bộ đang hiệu lực.';
}

// Ngôn ngữ (v3 đã loại bản dịch AI nháp; cờ is_ai_translated có thể vắng -> guard)
let languageWarning = '';
const hasVi = chunks.some(c => c.language_code === 'vi');
const hasEn = chunks.some(c => c.language_code === 'en');
const hasAiTrans = chunks.some(c => c.is_ai_translated === true);
if (prevData.response_language === 'vi' && !hasVi && hasEn) {
  languageWarning = 'Chỉ tìm thấy nguồn tiếng Anh. Câu trả lời là diễn giải tiếng Việt từ nguồn tiếng Anh.';
}
if (hasAiTrans) {
  languageWarning += (languageWarning ? ' ' : '') + '⚠ Một số nguồn là bản dịch AI.';
}

// Governance: tài liệu quá hạn rà soát nhưng VẪN còn hiệu lực
let governanceNote = '';
const dueReview = [...new Set(chunks.filter(c => c.lifecycle_state === 'due_review').map(c => c.document_code))];
if (dueReview.length > 0) {
  governanceNote = 'Một số tài liệu đã quá hạn rà soát định kỳ (vẫn còn hiệu lực): ' + dueReview.join(', ') + '.';
}

// Confidence theo combined_score sau rerank
const avgScore = chunks.reduce((s, c) => s + (parseFloat(c.combined_score) || 0), 0) / chunks.length;
let confidence = 'LOW';
if (avgScore >= 0.7 && chunks.length >= 3) confidence = 'HIGH';
else if (avgScore >= 0.55 && chunks.length >= 2) confidence = 'MEDIUM';

// Context
let contextText = '=== CONTEXT CHUNKS (đã lọc governance + rerank) ===\n\n';
chunks.forEach((c, i) => {
  contextText += `--- CHUNK ${i + 1} ---\n`;
  contextText += `Tài liệu: ${c.document_code} v${c.document_version} | Hiệu lực: ${c.lifecycle_state || 'effective'}\n`;
  contextText += `Ngôn ngữ: ${c.language_code} | Nguồn: ${c.source_type} (${c.source_category || 'internal'}) | Trust: ${c.trust_level}\n`;
  contextText += `Trang: ${c.page_number || 'N/A'} | Mục: ${c.section_code || 'N/A'} - ${c.section_title || 'N/A'}\n`;
  contextText += `Score: ${parseFloat(c.combined_score || 0).toFixed(3)} (sim ${parseFloat(c.similarity_score || 0).toFixed(2)} / fts ${parseFloat(c.fts_score || 0).toFixed(2)})\n`;
  contextText += `Nội dung:\n${c.content}\n\n`;
});

return [{ json: {
  ...prevData,
  chunks,
  has_sources: true,
  confidence,
  conflict_warning: conflictWarning,
  language_warning: languageWarning,
  governance_note: governanceNote,
  rerank_applied: inItem.rerank_applied || false,
  context_text: contextText
}}];

// ========================================
// Xây messages cho OpenAI Chat — prompt_version đọc động từ DB
// ========================================
const promptResult = $input.first().json;
const prevData = $('Process Search + Build Context').first().json;

const systemPrompt = promptResult.prompt_text || 'Bạn là GMP Validation AI Assistant. Trả lời bằng tiếng Việt với citation.';
const promptVersion = promptResult.version || 'unknown';

let warnings = '';
if (prevData.conflict_warning) warnings += '\nCẢNH BÁO CONFLICT: ' + prevData.conflict_warning;
if (prevData.language_warning) warnings += '\nCẢNH BÁO NGÔN NGỮ: ' + prevData.language_warning;
if (prevData.governance_note)  warnings += '\nGHI CHÚ GOVERNANCE: ' + prevData.governance_note;

const messages = [{ role: 'system', content: systemPrompt }];

if (prevData.conversation_history && prevData.conversation_history.length > 0) {
  messages.push(...prevData.conversation_history.slice(-4));
}

messages.push({
  role: 'user',
  content: prevData.context_text + warnings +
    '\n\n=== CÂU HỎI ===\n' + prevData.query +
    '\n\n=== YÊU CẦU ===\nTrả lời bằng tiếng Việt, trích dẫn mã tài liệu + phiên bản (vd: SOP-XXX v01) cho mỗi ý chính. CHỈ dùng thông tin trong CONTEXT, không bịa. Mức tin cậy: ' + prevData.confidence + '.'
});

return [{ json: { ...prevData, openai_messages: messages, prompt_version: promptVersion } }];

// ========================================
// Xử lý AI response + tạo SQL save (audit append-only + citation grounding) + sources cho FE
// ========================================
const aiResult = $input.first().json;
const prevData = $('Build AI Messages').first().json;

const answer = aiResult.choices?.[0]?.message?.content || 'Không thể tạo câu trả lời.';
const tokensUsed = aiResult.usage?.total_tokens || 0;

const esc = s => String(s ?? '').replace(/'/g, "''");
const escapedQuery  = esc(prevData.query);
const escapedAnswer = esc(answer);
const chunks = prevData.chunks || [];

// --- Source codes cho audit ---
const sourceCodes = chunks.map(c => c.document_code).filter(Boolean);

// --- Build citation VALUES cho ai_query_sources ---
const chunkValues = chunks.map((c, i) => {
  const chunkId  = c.chunk_id      ? `'${esc(c.chunk_id)}'::uuid`           : 'NULL';
  const docId    = c.document_id   ? `'${esc(c.document_id)}'::uuid`        : 'NULL';
  const docCode  = c.document_code  ? `'${esc(c.document_code)}'`           : 'NULL';
  const docVer   = c.document_version ? `'${esc(c.document_version)}'`      : 'NULL';
  const langCode = c.language_code  ? `'${c.language_code}'::language_code` : 'NULL';
  const pageNum  = c.page_number    || 'NULL';
  const secCode  = c.section_code   ? `'${esc(c.section_code)}'`            : 'NULL';
  const secTitle = c.section_title  ? `'${esc(c.section_title)}'`           : 'NULL';
  const srcType  = c.source_type    ? `'${c.source_type}'::source_type`     : 'NULL';
  const relScore = parseFloat(c.combined_score || 0);
  const grounded = c.chunk_id ? 'true' : 'false';
  const rank     = i + 1;
  const snip     = esc((c.content || '').substring(0, 150));
  return `((SELECT id FROM new_query), ${chunkId}, ${docId}, ${docCode}, ${docVer}, ${langCode}, ${pageNum}, ${secCode}, ${secTitle}, ${srcType}, ${relScore}, ${rank}, ${grounded}, ${rank}, '${snip}')`;
}).join(',\n    ');

// --- CTE sources INSERT (chỉ khi có chunks) ---
const sourcesCTE = chunks.length > 0 ? `,
sources_insert AS (
  INSERT INTO ai_query_sources
    (query_id, chunk_id, document_id, document_code, document_version,
     language_code, page_number, section_code, section_title, source_type,
     relevance_score, source_priority, grounded, citation_rank, snippet)
  VALUES
    ${chunkValues}
  RETURNING id
)` : '';

// --- Final SELECT: đảm bảo mọi CTE được materialized ---
const finalSelect = chunks.length > 0
  ? 'SELECT nq.id, au.log_id, (SELECT count(*)::int FROM sources_insert) AS sources_saved FROM new_query nq, audit_cte au'
  : 'SELECT nq.id, au.log_id FROM new_query nq, audit_cte au';

const saveSQL = `WITH new_query AS (
  INSERT INTO ai_queries
    (user_id, session_id, query_text, query_language, response_language,
     answer_text, confidence, model_used, prompt_version, tokens_used,
     has_conflict_warning, has_language_warning, filters)
  VALUES (
    '${prevData.user_id}'::uuid,
    ${prevData.session_id ? "'" + esc(prevData.session_id) + "'" : 'NULL'},
    '${escapedQuery}',
    '${prevData.response_language}'::language_code,
    '${prevData.response_language}'::language_code,
    '${escapedAnswer}',
    '${prevData.confidence}'::confidence_level,
    'gpt-4o-mini',
    '${esc(prevData.prompt_version)}',
    ${tokensUsed},
    ${!!prevData.conflict_warning},
    ${!!prevData.language_warning},
    '${JSON.stringify(prevData.filters).replace(/'/g, "''")}'::jsonb
  )
  RETURNING id
)${sourcesCTE},
audit_cte AS (
  SELECT write_audit_log(
    '${prevData.user_id}'::uuid,
    '${esc(prevData.user_email)}',
    '${esc(prevData.primary_role)}',
    'ai_query'::audit_action,
    '${escapedQuery.substring(0, 200)}',
    NULL,
    ARRAY[${sourceCodes.map(s => "'" + esc(String(s)) + "'").join(',')}]::text[],
    NULL, NULL, NULL, NULL, NULL,
    'gpt-4o-mini',
    '${esc(prevData.prompt_version)}',
    NULL, NULL,
    ${prevData.session_id ? "'" + esc(prevData.session_id) + "'" : 'NULL'}
  ) AS log_id
)
${finalSelect};`;

// --- Sources cho frontend (bổ sung grounded + chunk_id) ---
const sources = chunks.map(c => ({
  document_code:    c.document_code,
  document_title:   c.document_title,
  version:          c.document_version,
  language_code:    c.language_code,
  source_type:      c.source_type,
  source_category:  c.source_category   || null,
  trust_level:      (c.trust_level !== undefined && c.trust_level !== null) ? c.trust_level : null,
  lifecycle_state:  c.lifecycle_state   || 'effective',
  effective_date:   c.effective_date    || null,
  next_review_date: c.next_review_date  || null,
  page_number:      c.page_number,
  section_code:     c.section_code,
  section_title:    c.section_title,
  translation_status: c.translation_status || 'original',
  is_ai_translated: !!c.is_ai_translated,
  relevance_score:  parseFloat(c.combined_score || 0),
  similarity_score: parseFloat(c.similarity_score || 0),
  fts_score:        parseFloat(c.fts_score || 0),
  chunk_id:         c.chunk_id || null,
  grounded:         !!c.chunk_id,
  snippet:          (c.content || '').substring(0, 150) + '...'
}));

return [{ json: {
  save_sql: saveSQL,
  response: {
    success: true,
    answer:           answer,
    answer_language:  prevData.response_language || 'vi',
    sources:          sources,
    confidence:       prevData.confidence,
    conflict_warning: prevData.conflict_warning  || '',
    language_warning: prevData.language_warning  || '',
    governance_note:  prevData.governance_note   || '',
    retrieval: {
      rerank_applied: !!prevData.rerank_applied,
      expansion_used: !!prevData.expansion_used
    },
    model_used:     'gpt-4o-mini',
    prompt_version: prevData.prompt_version,
    disclaimer:     'Nội dung do AI tạo, cần người có chuyên môn xem xét trước khi dùng cho hồ sơ GMP chính thức.'
  }
}}];
